input.new_string:
interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface ScenarioResult {
  results: unknown[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const basePremium = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
    const withSurcharge = Math.floor(basePremium * 1.1);
    const premium = withSurcharge + 5;
    return { premium };
  });
  return { results };
};

