import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("should quote a single sword for a new customer (first contract) with processing fee", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("should quote a single amulet for a new customer (first contract) with processing fee", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("should quote two different items for a new customer (first contract)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 181 }] });
    });
    it("should quote a single component for a new customer (first contract)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [{ type: "component", material: "stone", enchantment: 0, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 32 }] });
    });
    it.todo("should quote three alike components with special group premium");
  });

  describe("Quote - surcharges", () => {
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should add both surcharges for a cursed and highly enchanted item");
  });

  describe("Quote - discounts", () => {
    it.todo("should apply 20% loyalty discount for customer with >= 2 years");
    it.todo("should apply 15% discount for a second contract (same customer)");
    it.todo("should apply both loyalty discount and repeat-contract discount");
  });

  describe("Claim - basic payout", () => {
    it.todo("should pay out damage minus 100G deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse 50% of damage for items with enchantment >= 8");
    it.todo("should fully reimburse damage for items made of dragon material");
  });
});

